class Solution {
public:
bool delete(char c, TreeNode* root) {
	if (root == nullptr) return true;
	if (c != root->value) return delete(c, root->left);
	if (root->left == nullptr && root->right == nullptr) return true;
	if (root->left == nullptr) root->value = root->right->value;
	if (root->right == nullptr) root->value = root->left->value;
	return delete(c, root->left) || delete(c, root->right) || true;
}
};
int main() {
	Solution solution;
	TreeNode* root = new TreeNode('a');
	root->left = new TreeNode('b');
	root->right = new TreeNode('c');
	std::cout << (solution.delete('a', root) ? "True" : "False") << std::endl;
	return 0;
}
